pragma solidity ^0.8.18;

contract Counter {
    uint256 public count;

    function increment() public {
        count += 1;
    }

    function decrement() public {
        require(count > 0, "count is already zero");
        count -= 1;
    }

    function getCount() public view returns (uint256) {
        return count;
    }
}

